def _cg_headers():
    h = {"accept": "application/json"}
    if CG_KEY:
        # Demo keys use x-cg-demo-api-key, Pro keys use x-cg-pro-api-key
        if CG_KEY.startswith("CG-"):
            h["x-cg-demo-api-key"] = CG_KEY
        else:
            h["x-cg-pro-api-key"] = CG_KEY
    return h

def _get(url: str, params: dict = None, timeout: int = 8) -> Optional[dict]:
    """Safe GET with timeout + error logging."""
    try:
        r = requests.get(url, params=params, timeout=timeout)
        r.raise_for_status()
        return r.json()
    except requests.exceptions.Timeout:
        logger.warning(f"Timeout: {url}")
    except requests.exceptions.HTTPError as e:
        logger.warning(f"HTTP {e.response.status_code}: {url}")
    except Exception as e:
        logger.warning(f"Error {url}: {e}")
    return None


